find /workspace/nexus/packages -name "*.test.ts" -not -path "*/node_modules/*" -exec wc -l {} + | awk '{
  if ($2 == "total") next
  pkg = $2
  sub("/workspace/nexus/packages/", "", pkg)
  split(pkg, parts, "/")
  if (parts[1] == "framework" || parts[1] == "plugins") {
    key = parts[1] "/" parts[2]
  } else {
    key = parts[1]
  }
  total[key] += $1
  count[key]++
}
END {
  for (k in total) printf "%-45s %5d files  %7d lines\n", k, count[k], total[k]
}' | sort -k4 -nr

