#!/usr/bin/env node
/**
 * One-shot: add `test:coverage` to every package.json under packages/.
 *
 * Derives the new script from the existing `test` script, preserving any
 * package-specific test-glob arguments. Inserts coverage flags before `--test`
 * and prepends `mkdir -p coverage && ` so the destination directory exists
 * before node tries to write the lcov report.
 */
import { readFileSync, writeFileSync } from 'node:fs';
import { execSync } from 'node:child_process';

const ROOT = '/workspace/nexus/packages';

const COVERAGE_FLAGS = [
  '--experimental-test-coverage',
  // Exclude the test files themselves
  "--test-coverage-exclude='**/*.test.ts'",
  "--test-coverage-exclude='**/*.test.js'",
  // Type declarations (no runtime to cover)
  "--test-coverage-exclude='**/*.d.ts'",
  // Test-only support code
  "--test-coverage-exclude='**/test-helpers.ts'",
  "--test-coverage-exclude='**/*-test-fixture.ts'",
  "--test-coverage-exclude='**/conformance/**'",
  // The output directory itself
  "--test-coverage-exclude='coverage/**'",
  // Dual reporter: spec → terminal, lcov → file
  '--test-reporter=spec',
  '--test-reporter-destination=stdout',
  '--test-reporter=lcov',
  '--test-reporter-destination=coverage/lcov.info',
].join(' ');

const pkgFiles = execSync(
  `find ${ROOT} -name package.json -not -path '*/node_modules/*'`,
  { encoding: 'utf8' },
).trim().split('\n').sort();

const updated = [];
const skipped = [];

for (const pkgFile of pkgFiles) {
  const json = JSON.parse(readFileSync(pkgFile, 'utf8'));
  const testScript = json.scripts?.test;
  if (!testScript) {
    skipped.push({ pkgFile, reason: 'no test script' });
    continue;
  }
  if (!testScript.includes('--test ')) {
    skipped.push({ pkgFile, reason: 'no --test flag in test script' });
    continue;
  }

  // Insert coverage flags right before `--test ` and prepend mkdir.
  const coverageScript =
    'mkdir -p coverage && ' +
    testScript.replace(/--test /, `${COVERAGE_FLAGS} --test `);

  json.scripts = json.scripts || {};
  // Preserve script ordering: build, test, test:coverage, typecheck.
  // Rebuild scripts object with deterministic order if all known keys present.
  const newScripts = {};
  const order = ['build', 'test', 'test:coverage', 'typecheck'];
  for (const key of order) {
    if (key === 'test:coverage') {
      newScripts[key] = coverageScript;
    } else if (json.scripts[key] !== undefined) {
      newScripts[key] = json.scripts[key];
    }
  }
  // Preserve any other scripts not in our canonical order
  for (const [k, v] of Object.entries(json.scripts)) {
    if (!(k in newScripts)) newScripts[k] = v;
  }
  json.scripts = newScripts;

  writeFileSync(pkgFile, JSON.stringify(json, null, 2) + '\n');
  updated.push(pkgFile.replace('/workspace/nexus/packages/', ''));
}

console.log(`Updated ${updated.length} package.json files:`);
for (const p of updated) console.log(`  ${p}`);
if (skipped.length) {
  console.log(`\nSkipped ${skipped.length}:`);
  for (const s of skipped) console.log(`  ${s.pkgFile}: ${s.reason}`);
}

