function pct(hit: number, found: number): string {
  if (found === 0) return '   —  ';
  return `${((hit / found) * 100).toFixed(2).padStart(6)}`;
}

function rawPct(hit: number, found: number): number {
  if (found === 0) return 100;
  return (hit / found) * 100;
}

