    );
  }
  console.log(rule);

  console.log(
    ` ${'TOTAL'.padEnd(40)} ${pct(tot.linesHit, tot.linesFound)}%  ${pct(
      tot.branchesHit,
      tot.branchesFound,
    )}%  ${pct(tot.funcsHit, tot.funcsFound)}%  ${String(tot.files).padStart(5)}`,
  );
  console.log(rule);
