  console.log(
    `Raw counters: ${tot.linesHit}/${tot.linesFound} lines, ` +
      `${tot.branchesHit}/${tot.branchesFound} branches, ` +
      `${tot.funcsHit}/${tot.funcsFound} functions across ${tot.files} files in ${pkgs.length} packages.`,
  );
