BEGIN { totalLines = 0 }
{ totalLines += $1; lines[NR] = $1 }
END {
  print "All files total:", totalLines
  cum = 0
  for (i=1; i<=NR; i++) {
    cum += lines[i]
    if (i == 10) printf "Top 10 files: %d lines (%.1f%% of total)\n", cum, cum/totalLines*100
    if (i == 22) printf "Top 22 files: %d lines (%.1f%% of total)\n", cum, cum/totalLines*100
    if (i == 50) printf "Top 50 files: %d lines (%.1f%% of total)\n", cum, cum/totalLines*100
  }
}'

