function globToRegex(glob: string): RegExp {
  // Transform glob to regex: ** -> .*, * -> [^/]*, escape other regex meta.
  let re = '';
  for (let i = 0; i < glob.length; i++) {
    if (glob[i] === '*' && glob[i + 1] === '*') {
      re += '.*';
      i++;
    } else if (glob[i] === '*') {
      re += '[^/]*';
    } else if ('.+?^${}()|[]\\'.includes(glob[i])) {
      re += '\\' + glob[i];
    } else {
      re += glob[i];
    }
  }
  return new RegExp('^' + re + '$');
}

