input.old_string:
/**
 * Capture the import + describe-eval + hook-define baseline for a single
 * test file by running it with a pattern that matches no test. The runner
 * still imports the module, evaluates describe callbacks (which register
 * subtests), and defines hooks — but executes no test bodies. Subtracting
 * this from each test's raw coverage isolates the test-specific lines.
 */
async function captureBaseline(
  testFile: string,
  pkg: ResolvedPackage,
  cacheDir: string,
  manifest: CacheManifest,
  noCache: boolean,
): Promise<Set<string>> {
  const fileMtime = fs.statSync(path.join(pkg.dir, testFile)).mtimeMs;
  const slug = crypto.createHash('sha256').update('baseline\0' + testFile).digest('hex').slice(0, 16);
  const lcovPath = path.join(cacheDir, `${slug}.lcov`);

  if (!noCache && manifest.baselines[testFile]) {
    const cached = manifest.baselines[testFile];
    if (cached.mtime === fileMtime && fs.existsSync(lcovPath)) {
      return parseLcovHits(fs.readFileSync(lcovPath, 'utf8'));
    }
  }

  const args = [
    ...coverageFlagsForFile(testFile),
    `--test-name-pattern=${NO_MATCH_PATTERN}`,
    '--test-reporter=lcov',
    `--test-reporter-destination=${lcovPath}`,
    '--test-reporter=spec',
    '--test-reporter-destination=/dev/null',
    '--test',
    path.join(pkg.dir, testFile),
  ];

  try { fs.unlinkSync(lcovPath); } catch { /* not present */ }
  await execNode(args, pkg.dir);

  if (!fs.existsSync(lcovPath) || fs.statSync(lcovPath).size === 0) {
    console.error(`  ⚠ baseline capture failed for ${testFile}`);
    return new Set();
  }

  manifest.baselines[testFile] = { mtime: fileMtime, lcovFile: `${slug}.lcov` };
  return parseLcovHits(fs.readFileSync(lcovPath, 'utf8'));
}

async function runOneTest(
  t: TestRecord,
  pkg: ResolvedPackage,
  cacheDir: string,
  manifest: CacheManifest,
  noCache: boolean,
  baseline: Set<string>,
): Promise<TestCoverage> {
  const start = Date.now();
  const hash = testHash(t);
  const lcovPath = path.join(cacheDir, `${hash}.lcov`);
  const fileMtime = fs.statSync(path.join(pkg.dir, t.file)).mtimeMs;

  // Cache lookup — note we cache the RAW lcov; baseline subtraction happens
  // here, so cached results stay valid even if baseline changes (rare).
  if (!noCache && manifest.entries[t.fullPath]) {
    const cached = manifest.entries[t.fullPath];
    if (cached.mtime === fileMtime && fs.existsSync(lcovPath)) {
      const raw = parseLcovHits(fs.readFileSync(lcovPath, 'utf8'));
      const coveredLines = subtractSet(raw, baseline);
      return {
        test: t,
        coveredLines,
        passed: true,
        durationMs: 0,
        fromCache: true,
      };
    }
  }

  // Fresh run
  const args = [
    ...coverageFlagsForFile(t.file),
    `--test-name-pattern=${patternFor(t)}`,
    '--test-reporter=lcov',
    `--test-reporter-destination=${lcovPath}`,
    '--test-reporter=spec',
    '--test-reporter-destination=/dev/null',
    '--test',
    path.join(pkg.dir, t.file),
  ];

  fs.mkdirSync(path.dirname(lcovPath), { recursive: true });
  try { fs.unlinkSync(lcovPath); } catch { /* not present */ }

  const result = await execNode(args, pkg.dir);
  const durationMs = Date.now() - start;

  const lcovExists = fs.existsSync(lcovPath);
  const lcovSize = lcovExists ? fs.statSync(lcovPath).size : 0;
  if (!lcovExists || lcovSize === 0) {
    console.error(
      `  ⚠ no coverage captured for ${t.fullPath} (exit ${result.code}); pattern=${patternFor(t)}`,
    );
    return {
      test: t,
      coveredLines: new Set(),
      passed: result.code === 0,
      durationMs,
      fromCache: false,
    };
  }

  const raw = parseLcovHits(fs.readFileSync(lcovPath, 'utf8'));
  const coveredLines = subtractSet(raw, baseline);

  manifest.entries[t.fullPath] = { mtime: fileMtime, lcovFile: `${hash}.lcov` };

  return {
    test: t,
    coveredLines,
    passed: result.code === 0,
    durationMs,
    fromCache: false,
  };
}

function subtractSet<T>(a: Set<T>, b: Set<T>): Set<T> {
  const out = new Set<T>();
  for (const x of a) if (!b.has(x)) out.add(x);
  return out;
}

