const cacheDir = path.join(pkg.dir, 'coverage', 'per-test');
fs.mkdirSync(cacheDir, { recursive: true });
const manifestPath = path.join(cacheDir, 'manifest.json');
const manifest: CacheManifest = fs.existsSync(manifestPath)
  ? { entries: {}, baselines: {}, ...JSON.parse(fs.readFileSync(manifestPath, 'utf8')) }
  : { entries: {}, baselines: {} };

// Phase 1: enumerate
const allTests = await discoverTests(pkg);
console.log(`Discovered ${allTests.length} tests.`);

const tests = opts.filter
  ? allTests.filter((t) => opts.filter!.test(t.fullPath))
  : allTests;
if (opts.filter) {
  console.log(`Filtered to ${tests.length} matching tests.`);
}
if (tests.length === 0) {
  die('no tests to analyze');
}

// Phase 2a: capture per-file baselines (one process per test file).
//   This isolates "import + describe-eval + hook-define" coverage, which
//   we then subtract from each test's raw coverage so the matrix reflects
//   only what the test BODY caused to execute.
const filesUsed = [...new Set(tests.map((t) => t.file))].sort();
console.log(`Capturing per-file baselines for ${filesUsed.length} files...`);
const baselines = new Map<string, Set<string>>();
await runPool(filesUsed, opts.workers, async (f) => {
  const b = await captureBaseline(f, pkg, cacheDir, manifest, opts.noCache);
  baselines.set(f, b);
});

